using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public int bonusDamage = 0;

    public Text healthText;
    public Text currencyText;
    public Text damageText;

    private void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        RefreshUI();
    }

    public int GetTotalDamage()
    {
        return baseDamage + bonusDamage;
    }

    public void TakeDamage(int incomingDamage, int defense)
    {
        int finalDamage = CalculateDamageTaken(incomingDamage, defense);
        currentHealth -= finalDamage;
        if (currentHealth < 0)
            currentHealth = 0;
        RefreshUI();
    }

    public int CalculateDamageTaken(int incomingDamage, int defense)
    {
        int reducedDamage = incomingDamage - defense;
        if (reducedDamage < 1)
            reducedDamage = 1;
        return reducedDamage;
    }

    public bool SpendCurrency(int amount)
    {
        if (amount <= 0)
            return false;

        if (currency < amount)
            return false;

        currency -= amount;
        RefreshUI();
        return true;
    }

    public void AddCurrency(int amount)
    {
        if (amount <= 0)
            return;

        currency += amount;
        RefreshUI();
    }

    public void Heal(int amount)
    {
        if (amount <= 0)
            return;

        currentHealth += amount;
        if (currentHealth > maxHealth)
            currentHealth = maxHealth;
        RefreshUI();
    }

    public void AddBonusDamage(int amount)
    {
        if (amount <= 0)
            return;

        bonusDamage += amount;
        RefreshUI();
    }

    public void RefreshUI()
    {
        if (healthText != null)
            healthText.text = "Health: " + currentHealth + "/" + maxHealth;

        if (currencyText != null)
            currencyText.text = "Currency: " + currency;

        if (damageText != null)
            damageText.text = "Damage: " + GetTotalDamage();
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;
    public int defense = 2;
    public int contactDamage = 8;

    public void TakeHit(int attackerDamage)
    {
        int finalDamage = CalculateDamageReceived(attackerDamage, defense);
        currentHealth -= finalDamage;
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Destroy(gameObject);
        }
    }

    public int CalculateDamageReceived(int attackerDamage, int targetDefense)
    {
        int result = attackerDamage - targetDefense;
        if (result < 1)
            result = 1;
        return result;
    }
}

public class PlayerCombat : MonoBehaviour
{
    public PlayerStats playerStats;

    public void AttackEnemy(Enemy enemy)
    {
        if (enemy == null || playerStats == null)
            return;

        int totalDamage = playerStats.GetTotalDamage();
        enemy.TakeHit(totalDamage);
    }

    public void ReceiveEnemyHit(Enemy enemy, int playerDefense)
    {
        if (enemy == null || playerStats == null)
            return;

        playerStats.TakeDamage(enemy.contactDamage, playerDefense);
    }
}

public class ShopItem
{
    public string itemName;
    public int basePrice;
    public int level;
    public int priceIncreasePerLevel;
    public int damageBonusPerPurchase;
    public int healAmountPerPurchase;

    public ShopItem(string itemName, int basePrice, int priceIncreasePerLevel, int damageBonusPerPurchase, int healAmountPerPurchase)
    {
        this.itemName = itemName;
        this.basePrice = basePrice;
        this.priceIncreasePerLevel = priceIncreasePerLevel;
        this.damageBonusPerPurchase = damageBonusPerPurchase;
        this.healAmountPerPurchase = healAmountPerPurchase;
        level = 0;
    }

    public int GetCurrentPrice()
    {
        return basePrice + (level * priceIncreasePerLevel);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;

    public string damageUpgradeName = "Sword Upgrade";
    public int damageUpgradeBasePrice = 100;
    public int damageUpgradePriceIncrease = 50;
    public int damageUpgradeAmount = 5;

    public string healthPotionName = "Health Potion";
    public int healthPotionBasePrice = 75;
    public int healthPotionPriceIncrease = 0;
    public int healthPotionHealAmount = 25;

    public Text damageUpgradePriceText;
    public Text potionPriceText;

    private ShopItem damageUpgradeItem;
    private ShopItem healthPotionItem;

    private void Start()
    {
        damageUpgradeItem = new ShopItem(
            damageUpgradeName,
            damageUpgradeBasePrice,
            damageUpgradePriceIncrease,
            damageUpgradeAmount,
            0
        );

        healthPotionItem = new ShopItem(
            healthPotionName,
            healthPotionBasePrice,
            healthPotionPriceIncrease,
            0,
            healthPotionHealAmount
        );

        RefreshShopUI();
    }

    public void BuyDamageUpgrade()
    {
        if (playerStats == null || damageUpgradeItem == null)
            return;

        int price = damageUpgradeItem.GetCurrentPrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.AddBonusDamage(damageUpgradeItem.damageBonusPerPurchase);
            damageUpgradeItem.level++;
            RefreshShopUI();
        }
    }

    public void BuyHealthPotion()
    {
        if (playerStats == null || healthPotionItem == null)
            return;

        int price = healthPotionItem.GetCurrentPrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.Heal(healthPotionItem.healAmountPerPurchase);
            healthPotionItem.level++;
            RefreshShopUI();
        }
    }

    public void RefreshShopUI()
    {
        if (damageUpgradePriceText != null && damageUpgradeItem != null)
            damageUpgradePriceText.text = damageUpgradeItem.itemName + ": " + damageUpgradeItem.GetCurrentPrice();

        if (potionPriceText != null && healthPotionItem != null)
            potionPriceText.text = healthPotionItem.itemName + ": " + healthPotionItem.GetCurrentPrice();
    }
}